public String alarmClock(int day, boolean vacation)
{
    if ((day > 1 && day < 6) && (!vacation))
        return "10:00";
    if ((day == 0 || day == 6) && (!vacation))
        return "7:00";
    if ((day > 1 && day < 6) && (vacation))
        return "off";
    if ((day == 0 || day == 6) && (vacation))
        return "10:00";
}

public int countClumps(int[] nums)
{
    int clumps = 0;
    for (int i = 0; i < nums.length - 1; i++)
    {
        if (nums[i] == nums[i + 1])
            {
                clumps++;
            }
    }
    return clumps;
}

